/* eslint-disable react/jsx-key */
import React, { useState } from 'react';
import { Rate } from '..';
import { Divider } from '../../divider';
import EmojiFilled from '@universe-design/icons-react/EmojiFilled';
import CollectionOutlined from '@universe-design/icons-react/CollectionOutlined';
import BurnlifeDayOutlined from '@universe-design/icons-react/BurnlifeDayOutlined';
import BurnlifeHourOutlined from '@universe-design/icons-react/BurnlifeHourOutlined';
import BurnlifeMinuteOutlined from '@universe-design/icons-react/BurnlifeMinuteOutlined';
import BurnlifeWeekOutlined from '@universe-design/icons-react/BurnlifeWeekOutlined';

export default {
  title: 'Components/Rate/临时示例', // 注意：这里需要修改成自己对应 Component name。
  component: Rate,
};

export const DifferentStates = () => {
  const [value, setValue] = useState(2);
  const tips = ['terrible', 'bad', 'normal', 'good', 'wonderful'];
  const des = ['please click to rate', 'terrible', 'bad', 'normal', 'good', 'wonderful'];

  const customIcons = [
    <BurnlifeDayOutlined />,
    <BurnlifeHourOutlined />,
    <BurnlifeMinuteOutlined />,
    <BurnlifeWeekOutlined />,
    <EmojiFilled />,
  ];

  return (
    <div>
      <Divider text="基础" />
      <Rate tooltips={tips} /> <br />
      <Rate value={value} onHoverChange={v => setValue(v)} />
      <br />
      <Divider text="不展示描述" />
      <Rate showDescriptions={false} />
      <br />
      <Divider text="半选" />
      <Rate allowHalf tooltips={tips} />
      <Divider text="自定义 描述" />
      <Rate tooltips={tips} descriptions={des} />
      <Divider text="自定义步长" />
      <Rate readonly defaultValue={0.5} />
      <br />
      <Rate readonly defaultValue={0.1} />
      <br />
      <Rate readonly defaultValue={3.7} />
      <br />
      <Rate readonly defaultValue={2.3} />
      <br />
      <Divider text="自定义数量" />
      <Rate count={10} descriptions={[...des, ...des]} />
      <Divider text="自定义字符" />
      <Rate character="A" allowHalf />
      <br />
      <Rate character={<CollectionOutlined />} allowHalf />
      <br />
      <Rate character={({ index }) => customIcons[index]} />
      <br />
    </div>
  );
};

export const Controller = () => {
  const [value, setValue] = React.useState<number>(0);
  const onHoverChange = (v: number) => console.log('onHoverChange', v);
  const onChange = (v: number) => {
    console.log('onChange', v);
    setValue(v);
  };

  return <Rate value={value} onHoverChange={onHoverChange} onChange={onChange} />;
};
